<?php declare(strict_types=1);use App\Support\View;$base='/people/'.$person->id.'/capacity';?>
<div class="d-flex justify-content-between align-items-start mb-4"><div><p class="text-secondary mb-1"><?= View::escape($person->positionLabel()) ?> — <?= View::escape($person->affiliation??'No affiliation') ?></p><h1><?= View::escape($person->fullName()) ?> capacity</h1><p>Standard monthly capacity: <strong><?= View::escape($person->defaultMonthlyCapacityHours) ?> hours</strong></p></div><?php if($isAdmin):?><a class="btn btn-primary" href="<?= View::escape($urls->to('/admin/people/'.$person->id.'/capacity/overrides/create')) ?>">Add override</a><?php endif;?></div>
<div class="d-flex justify-content-between align-items-center mb-3"><a href="<?= View::escape($urls->to($base,['year'=>$year-1])) ?>">← <?= $year-1 ?></a><form class="d-flex gap-2" method="get" action="<?= View::escape($urls->to($base)) ?>"><label class="visually-hidden" for="year">Year</label><input class="form-control" id="year" name="year" value="<?= $year ?>" inputmode="numeric"><button class="btn btn-outline-primary">Go</button></form><a href="<?= View::escape($urls->to($base,['year'=>$year+1])) ?>"><?= $year+1 ?> →</a></div>
<div class="table-responsive bg-white border rounded"><table class="table table-striped align-middle mb-0"><thead><tr><th>Month</th><th>Capacity</th><th>Source</th><th>Planned</th><th>Actual</th><th>Planned remaining</th><th>Actual remaining</th><th>Status</th><?php if($isAdmin):?><th>Actions</th><?php endif;?></tr></thead><tbody><?php foreach($months as$m):?><tr class="<?= $m->plannedStatus($decimals)==='overallocated'||$m->actualStatus($decimals)==='overallocated'?'table-warning':'' ?>"><td><?= (new DateTimeImmutable(sprintf('%04d-%02d-01',$year,$m->month)))->format('F') ?></td><td><?= View::escape($m->capacity->effectiveHours) ?></td><td><?= View::escape(ucfirst($m->capacity->source)) ?></td><td><?= View::escape($m->plannedHours) ?></td><td><?= View::escape($m->actualHours) ?></td><td><?= View::escape($m->plannedRemaining($decimals)) ?></td><td><?= View::escape($m->actualRemaining($decimals)) ?></td><td>Planned: <?= View::escape($m->plannedStatus($decimals)) ?><br>Actual: <?= View::escape($m->actualStatus($decimals)) ?><?php if($m->plannedWarning($decimals)):?><br><span class="text-danger"><?= View::escape($m->plannedWarning($decimals)) ?></span><?php endif;?><?php if($m->actualWarning($decimals)):?><br><span class="text-danger"><?= View::escape($m->actualWarning($decimals)) ?></span><?php endif;?></td><?php if($isAdmin):?><td><?php if($m->overrideId):?><a class="btn btn-sm btn-outline-primary" href="<?= View::escape($urls->to('/admin/people/'.$person->id.'/capacity/overrides/'.$m->overrideId.'/edit')) ?>">Edit</a><?php else:?><a class="btn btn-sm btn-outline-secondary" href="<?= View::escape($urls->to('/admin/people/'.$person->id.'/capacity/overrides/create',['year'=>$year,'month'=>$m->month])) ?>">Override</a><?php endif;?></td><?php endif;?></tr><?php endforeach;?></tbody></table></div>
<p class="form-text mt-3">Capacity is person-level availability across all projects. It is independent from project hours-per-PM conversion factors. Warnings are non-blocking.</p>
